import React from "react";
import { useEffect } from 'react';

const services = [
  {
    icon: "☁️",
    title: "Cloud & Infrastructure",
    items: [
      "Déploiement sur AWS / Firebase",
      "Architecture IaaS, PaaS, SaaS",
      "Virtualisation & performance",
    ],
  },
  {
    icon: "⚛️",
    title: "Développement Web Full Stack",
    items: [
      "Applications React & Next.js",
      "APIs REST avec Express.js",
      "Intégration MongoDB & Firebase",
    ],
  },
  {
    icon: "🔐",
    title: "Sécurité & Authentification",
    items: [
      "JWT & gestion des accès",
      "Réinitialisation sécurisée",
      "Protection des données",
    ],
  },
  {
    icon: "🛠️",
    title: "DevOps & Automatisation",
    items: [
      "Git / GitHub Workflows",
      "Pipelines CI/CD",
      "Déploiement et monitoring",
    ],
  },
];

export default function Services() {
  useEffect(() => {
    // Scroll reveal pour les cartes
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.classList.add('visible');
          observer.unobserve(e.target);
        }
      });
    }, { threshold: 0.1 });

    document.querySelectorAll('.service-card').forEach(el => observer.observe(el));

    return () => observer.disconnect();
  }, []);

  return (
    <section className="section services-section">
      <div className="services-wrap">
        {/* Header */}
        <div className="services-header reveal-left">
          <span className="section-label">Ce que je fais</span>
          <h2 className="section-title">Services & <span>Expertises</span></h2>
          <div className="section-underline" />
        </div>

        <p className="services-desc reveal-right">
          Des solutions numériques innovantes pour moderniser vos projets,
          renforcer la sécurité et accélérer votre croissance.
        </p>

        {/* Grid de services */}
        <div className="services-grid stagger">
          {services.map((s, index) => (
            <div 
              key={s.title} 
              className="service-card reveal"
              style={{ transitionDelay: `${index * 0.1}s` }}
            >
              {/* Effet de glow au hover */}
              <div className="service-glow" />

              {/* Icon avec animation */}
              <div className="service-icon-wrap">
                <div className="service-icon-bg" />
                <span className="service-icon">{s.icon}</span>
              </div>

              {/* Titre */}
              <h3 className="service-title">{s.title}</h3>

              {/* Liste avec effet */}
              <ul className="service-list">
                {s.items.map((item, itemIndex) => (
                  <li key={item} className="service-item">
                    <span className="item-dot" />
                    <span className="item-text">{item}</span>
                  </li>
                ))}
              </ul>

              {/* Lien vers plus d'info */}
              <a href="#" className="service-link">
                <span>En savoir plus</span>
                <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                  <path d="M3 8h10M10 5l3 3-3 3" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                </svg>
              </a>
            </div>
          ))}
        </div>

        {/* Boutons d'action */}
        <div className="services-actions reveal">
          <button className="btn-primary">
            <span>Démarrer un projet</span>
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M3 8h10M10 5l3 3-3 3" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
            </svg>
          </button>
          <button className="btn-outline">
            <span>Contacter</span>
          </button>
        </div>
      </div>
    </section>
  );
}
